<?php

namespace Database\Seeders;

use App\Models\Account;
use App\Models\SitePage;
use Illuminate\Database\Seeder;

class SitePagesSeeder extends Seeder
{
    public function run(): void
    {
        $account = Account::query()->first();
        if (! $account) {
            return;
        }

        $pages = [
            ['slug' => 'products', 'template' => 'products', 'sort' => 10, 'ar' => ['المنتجات', 'اكتشف مجموعتنا المختارة من المنتجات والعروض المتوفرة.'], 'en' => ['Products', 'Discover our curated collection of products and available offers.']],
            ['slug' => 'about-us', 'template' => 'about', 'sort' => 20, 'ar' => ['من نحن', 'نؤمن أن الجودة تبدأ من الاختيار الصحيح والثقة المستمرة.', '<h2>قصتنا</h2><p>نختار منتجاتنا بعناية ونبني تجربتنا حول الجودة والوضوح وخدمة العميل. هدفنا أن نوفر لك منتجات موثوقة وتجربة سهلة من أول زيارة وحتى استلام الطلب.</p><h2>قيمنا</h2><p>الجودة، المصداقية، سرعة الاستجابة، والاهتمام بالتفاصيل هي الأساس في كل ما نقدمه.</p>'], 'en' => ['About us', 'We believe quality begins with the right choice and lasting trust.', '<h2>Our story</h2><p>We carefully select our products and build our experience around quality, clarity, and customer care.</p><h2>Our values</h2><p>Quality, credibility, responsiveness, and attention to detail guide everything we do.</p>']],
            ['slug' => 'contact-us', 'template' => 'contact', 'sort' => 30, 'ar' => ['تواصل معنا', 'يسعدنا سماعك والإجابة عن استفساراتك ومساعدتك.', '<h2>نحن قريبون منك</h2><p>أرسل رسالتك من النموذج وسيتواصل معك فريقنا في أقرب وقت ممكن.</p>'], 'en' => ['Contact us', 'We are happy to hear from you and answer your questions.', '<h2>We are here for you</h2><p>Send your message and our team will get back to you as soon as possible.</p>']],
            ['slug' => 'privacy-policy', 'template' => 'privacy', 'sort' => 40, 'ar' => ['سياسة الخصوصية', 'توضح هذه الصفحة كيفية جمع بياناتك واستخدامها وحمايتها.', '<h2>البيانات التي نجمعها</h2><p>نجمع البيانات التي تقدمها عند التواصل معنا أو إرسال طلب، مثل الاسم ورقم الهاتف والبريد الإلكتروني وبيانات الطلب.</p><h2>استخدام البيانات</h2><p>تستخدم البيانات لتنفيذ الطلبات، التواصل معك، تحسين الخدمة، وقياس أداء الحملات. لا نبيع بياناتك الشخصية لطرف ثالث.</p><h2>حماية البيانات</h2><p>نتخذ إجراءات مناسبة لحماية البيانات من الوصول أو الاستخدام غير المصرح به.</p>'], 'en' => ['Privacy policy', 'This page explains how we collect, use, and protect your information.', '<h2>Information we collect</h2><p>We collect information you provide when contacting us or submitting an order.</p><h2>How we use it</h2><p>We use data to fulfill orders, communicate with you, improve service, and measure campaign performance.</p><h2>Data protection</h2><p>We take reasonable measures to protect your information from unauthorized access or use.</p>']],
            ['slug' => 'terms-and-conditions', 'template' => 'terms', 'sort' => 50, 'ar' => ['الأحكام والشروط', 'تعرّف على الشروط المنظمة لاستخدام الموقع وشراء المنتجات والخدمات.', '<p><strong>آخر تحديث: يوليو 2026</strong></p><h2>1. قبول الشروط</h2><p>باستخدامك هذا الموقع أو إرسال طلب، فإنك تقر بقراءة هذه الأحكام والموافقة عليها. إذا لم توافق عليها، يرجى التوقف عن استخدام الموقع.</p><h2>2. المنتجات والمعلومات</h2><p>نبذل عناية معقولة لعرض أوصاف وصور وأسعار دقيقة. قد تختلف الألوان أو العبوات قليلًا بحسب الشاشة أو تحديثات المورد، ولا يؤثر ذلك في الخصائص الأساسية للمنتج.</p><h2>3. الطلبات والأسعار</h2><p>يُعد إرسال الطلب طلبًا للشراء وليس قبولًا نهائيًا. يصبح الطلب مؤكدًا بعد مراجعته والتواصل مع العميل عند الحاجة. تظهر الأسعار والعملة وأي رسوم توصيل قبل تأكيد الطلب.</p><h2>4. الدفع والتوصيل</h2><p>تتوفر طرق الدفع والتوصيل المبينة أثناء الطلب. على العميل تقديم عنوان ورقم هاتف صحيحين، وقد تتغير مدة التسليم وفق المنطقة والظروف التشغيلية.</p><h2>5. الإلغاء والاستبدال والاسترجاع</h2><p>تُراجع طلبات الإلغاء أو الاستبدال أو الاسترجاع وفق حالة الطلب وطبيعة المنتج. يرجى التواصل معنا فورًا عند وجود منتج تالف أو غير مطابق مع إرفاق ما يوضح الحالة.</p><h2>6. الاستخدام المقبول</h2><p>لا يجوز إساءة استخدام الموقع، أو محاولة تعطيله، أو إدخال بيانات مضللة، أو استخدام المحتوى والعلامات التجارية دون إذن.</p><h2>7. حدود المسؤولية</h2><p>نقدم الموقع بالمستوى المتاح ونسعى لاستمراريته، لكن قد تحدث أعمال صيانة أو انقطاعات خارجة عن السيطرة. لا تستبعد هذه الشروط أي حقوق لا يجوز استبعادها قانونًا.</p><h2>8. التعديلات والتواصل</h2><p>قد نحدّث هذه الأحكام عند تطوير الخدمات. يسري الإصدار المنشور من تاريخ تحديثه. لأي استفسار، تواصل معنا عبر بيانات الاتصال الموضحة في الموقع.</p>'], 'en' => ['Terms and conditions', 'Review the terms governing use of this website and purchases of products and services.', '<p><strong>Last updated: July 2026</strong></p><h2>1. Acceptance</h2><p>By using this website or placing an order, you acknowledge that you have read and accepted these terms. If you do not agree, please stop using the website.</p><h2>2. Products and information</h2><p>We take reasonable care to present accurate descriptions, images, and prices. Colors or packaging may vary slightly due to displays or supplier updates without changing essential product characteristics.</p><h2>3. Orders and prices</h2><p>Submitting an order is a request to purchase, not final acceptance. An order is confirmed after review and customer contact where needed. Prices, currency, and delivery charges are shown before confirmation.</p><h2>4. Payment and delivery</h2><p>Available payment and delivery methods are shown during ordering. Customers must provide an accurate address and phone number. Delivery times may vary by location and operating conditions.</p><h2>5. Cancellations, exchanges, and returns</h2><p>Requests are reviewed according to order status and product type. Contact us promptly if an item is damaged or not as described and provide supporting details.</p><h2>6. Acceptable use</h2><p>You may not misuse or disrupt the website, submit misleading information, or use our content and trademarks without permission.</p><h2>7. Limitation of liability</h2><p>We provide the website on an available basis and work to maintain continuity, but maintenance or circumstances beyond our control may cause interruptions. These terms do not exclude rights that cannot legally be excluded.</p><h2>8. Changes and contact</h2><p>We may update these terms as our services evolve. The published version applies from its update date. Contact us using the details displayed on the website if you have questions.</p>']],
        ];

        foreach ($pages as $data) {
            $page = SitePage::updateOrCreate(['account_id' => $account->id, 'slug' => $data['slug']], ['template' => $data['template'], 'status' => 'published', 'show_in_header' => true, 'show_in_footer' => true, 'sort_order' => $data['sort']]);
            foreach (['ar', 'en'] as $locale) {
                $translation = $data[$locale];
                $page->translations()->updateOrCreate(['locale' => $locale], ['title' => $translation[0], 'navigation_label' => $translation[0], 'excerpt' => $translation[1], 'content' => $translation[2] ?? null, 'seo_title' => $translation[0], 'seo_description' => $translation[1]]);
            }
        }
    }
}
